function validateRouteParams(url) {
  const pattern = /users/([a-zA-Z0-9]+)/;
  const match = url.match(pattern);
  if (match) {
    const id = match[1];
    if (id % 2 === 0) {
      res.send(`id: ${id}`);
    } else {
      res.status(404).send('Error: Invalid route parameter');
    }
  } else {
    res.status(404).send('Error: Invalid route parameter');
  }
}

